BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Cardiac Tamponade' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Cardiac Tamponade', 'Beck''s triad, diagnosis, and emergency management', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Cardiac Tamponade (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Cardiac Tamponade - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Definition?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Definition?', '[{"id": "a", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "b", "text": "Cardiac tamponade is fluid accumulation in the pericardial sac that compresses the heart."}, {"id": "c", "text": "Tamponade is a benign condition that can always wait for routine follow-up."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Cardiac tamponade is fluid accumulation in the pericardial sac that compresses the heart. Treat as an emergency because rapid deterioration and arrest can occur.', 'Cardiac Tamponade - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Hemodynamic mechanism?', 'During rapid handoff, which interpretation is most accurate for Hemodynamic mechanism?', '[{"id": "a", "text": "Recognize obstructive shock pattern when hypotension and poor perfusion progress."}, {"id": "b", "text": "Tamponade increases preload by compressing the ventricles."}, {"id": "c", "text": "Tamponade is primarily distributive shock from vasodilation in this note."}, {"id": "d", "text": "This finding is more consistent with Beck triad."}]'::jsonb, '["a"]'::jsonb, 'Correct because Increased intrapericardial pressure compresses all four chambers and causes obstructive shock. Recognize obstructive shock pattern when hypotension and poor perfusion progress.', 'Cardiac Tamponade - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Acute volume threshold?', 'The nurse must prioritize interventions. Which statement best reflects Acute volume threshold?', '[{"id": "a", "text": "This finding is more consistent with Muffled heart sounds meaning."}, {"id": "b", "text": "Only massive chronic effusions can cause tamponade in this note."}, {"id": "c", "text": "Volume rate of accumulation is irrelevant in tamponade risk."}, {"id": "d", "text": "As little as 150–200 mL acutely accumulated fluid can cause tamponade."}]'::jsonb, '["d"]'::jsonb, 'Correct because As little as 150–200 mL acutely accumulated fluid can cause tamponade. Do not underestimate small but rapidly accumulating effusions.', 'Cardiac Tamponade - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Cause profile?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Cause profile?', '[{"id": "a", "text": "This finding is more consistent with JVD mechanism."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "Screen etiology rapidly while preparing definitive decompression."}, {"id": "d", "text": "Tamponade is only caused by isolated dehydration in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericarditis is the most common cause, with trauma, post-op bleeding, malignancy, and aortic dissection also listed. Screen etiology rapidly while preparing definitive decompression.', 'Cardiac Tamponade - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Additional causes?', 'Which clinical judgment is most consistent with Additional causes?', '[{"id": "a", "text": "Tamponade causes are limited to congenital defects in this note."}, {"id": "b", "text": "Radiation therapy cannot contribute to tamponade in this note."}, {"id": "c", "text": "Additional causes include MI free-wall rupture, iatrogenic catheterization complications, SLE, uremia, and radiation therapy."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Additional causes include MI free-wall rupture, iatrogenic catheterization complications, SLE, uremia, and radiation therapy. Integrate procedural and systemic risk factors into rapid triage.', 'Cardiac Tamponade - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Beck triad?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Beck triad?', '[{"id": "a", "text": "Escalate immediately when triad features cluster together."}, {"id": "b", "text": "This finding is more consistent with Pulsus paradoxus."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Hypertension is part of Beck triad in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Beck triad consists of muffled heart sounds, JVD, and hypotension. Escalate immediately when triad features cluster together.', 'Cardiac Tamponade - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Muffled heart sounds meaning?', 'During rapid handoff, which interpretation is most accurate for Muffled heart sounds meaning?', '[{"id": "a", "text": "This finding is more consistent with Compensatory tachycardia."}, {"id": "b", "text": "Muffled tones rule out tamponade in this note."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Muffled tones occur because pericardial fluid dampens auscultated sounds."}]'::jsonb, '["d"]'::jsonb, 'Correct because Muffled tones occur because pericardial fluid dampens auscultated sounds. Correlate difficult auscultation with other tamponade signs rather than dismissing technique.', 'Cardiac Tamponade - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects JVD mechanism?', 'The nurse must prioritize interventions. Which statement best reflects JVD mechanism?', '[{"id": "a", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "b", "text": "JVD is unrelated to right-heart filling in this note."}, {"id": "c", "text": "Use venous congestion findings to support obstructive physiology."}, {"id": "d", "text": "JVD in tamponade represents low venous pressure in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because JVD reflects impaired right-heart filling and backed-up venous pressure. Use venous congestion findings to support obstructive physiology.', 'Cardiac Tamponade - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Hypotension pattern?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Hypotension pattern?', '[{"id": "a", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "b", "text": "Hypotension occurs from reduced cardiac output and often presents with narrow pulse pressure."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Hypotension is not expected in tamponade according to this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Hypotension occurs from reduced cardiac output and often presents with narrow pulse pressure. Treat narrowing pulse pressure with falling BP as decompensation.', 'Cardiac Tamponade - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Pulsus paradoxus?', 'Which clinical judgment is most consistent with Pulsus paradoxus?', '[{"id": "a", "text": "Use this measurement to reinforce tamponade suspicion in unstable patients."}, {"id": "b", "text": "This finding is more consistent with Electrical alternans."}, {"id": "c", "text": "A 2 mmHg inspiratory change defines pulsus paradoxus in this note."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pulsus paradoxus is a >10 mmHg systolic BP drop during inspiration. Use this measurement to reinforce tamponade suspicion in unstable patients.', 'Cardiac Tamponade - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Compensatory tachycardia?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Compensatory tachycardia?', '[{"id": "a", "text": "This finding is more consistent with Other EKG clues."}, {"id": "b", "text": "Heart rate has no monitoring value in tamponade in this note."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Tachycardia is listed as a compensatory sign in tamponade."}]'::jsonb, '["d"]'::jsonb, 'Correct because Tachycardia is listed as a compensatory sign in tamponade. Interpret rising heart rate with perfusion decline as compensation failure risk.', 'Cardiac Tamponade - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Perfusion decline?', 'During rapid handoff, which interpretation is most accurate for Perfusion decline?', '[{"id": "a", "text": "This finding is more consistent with Echo diagnosis."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Prioritize perfusion rescue and definitive decompression."}]'::jsonb, '["d"]'::jsonb, 'Correct because Cool clammy skin and decreased urine output are signs of shock/perfusion compromise. Prioritize perfusion rescue and definitive decompression.', 'Cardiac Tamponade - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Respiratory/general signs?', 'The nurse must prioritize interventions. Which statement best reflects Respiratory/general signs?', '[{"id": "a", "text": "Dysphagia cannot occur with larger effusions in this note."}, {"id": "b", "text": "This finding is more consistent with Chest X-ray clue."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Dyspnea, orthopnea, anxiety/restlessness, and possible dysphagia are listed additional findings."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dyspnea, orthopnea, anxiety/restlessness, and possible dysphagia are listed additional findings. Interpret escalating respiratory distress and anxiety as potential hemodynamic deterioration.', 'Cardiac Tamponade - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Electrical alternans?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Electrical alternans?', '[{"id": "a", "text": "Treat electrical alternans as a red-flag trigger for immediate escalation."}, {"id": "b", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Alternans excludes pericardial fluid in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Electrical alternans (alternating QRS amplitude) is pathognomonic and tamponade until proven otherwise. Treat electrical alternans as a red-flag trigger for immediate escalation.', 'Cardiac Tamponade - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Other EKG clues?', 'Which clinical judgment is most consistent with Other EKG clues?', '[{"id": "a", "text": "Tamponade cannot coexist with pericarditis EKG changes in this note."}, {"id": "b", "text": "High-voltage QRS is the defining tamponade pattern in this note."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Low-voltage QRS and sinus tachycardia are common; diffuse ST elevation can appear if pericarditis is the cause."}]'::jsonb, '["d"]'::jsonb, 'Correct because Low-voltage QRS and sinus tachycardia are common; diffuse ST elevation can appear if pericarditis is the cause. Integrate EKG pattern with etiology and bedside instability.', 'Cardiac Tamponade - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Echo diagnosis?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Echo diagnosis?', '[{"id": "a", "text": "Expedite bedside echo in unstable patients with suspected tamponade."}, {"id": "b", "text": "Chest X-ray is the gold standard in this note."}, {"id": "c", "text": "This finding is more consistent with Small-volume benefit."}, {"id": "d", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}]'::jsonb, '["a"]'::jsonb, 'Correct because Echocardiogram is the gold standard and shows effusion with chamber compression. Expedite bedside echo in unstable patients with suspected tamponade.', 'Cardiac Tamponade - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Chest X-ray clue?', 'During rapid handoff, which interpretation is most accurate for Chest X-ray clue?', '[{"id": "a", "text": "Water-bottle silhouette confirms acute coronary occlusion in this note."}, {"id": "b", "text": "Chest X-ray may show an enlarged water-bottle cardiac silhouette."}, {"id": "c", "text": "Normal silhouette excludes tamponade in this note."}, {"id": "d", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}]'::jsonb, '["b"]'::jsonb, 'Correct because Chest X-ray may show an enlarged water-bottle cardiac silhouette. Use X-ray as supportive evidence, not a delay to treatment.', 'Cardiac Tamponade - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Pericardiocentesis emergency?', 'The nurse must prioritize interventions. Which statement best reflects Pericardiocentesis emergency?', '[{"id": "a", "text": "This finding is more consistent with Supportive preload strategy."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "Prepare urgently and do not delay for nonessential steps."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Immediate pericardiocentesis is the emergency treatment. Prepare urgently and do not delay for nonessential steps.', 'Cardiac Tamponade - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Pericardiocentesis technique?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Pericardiocentesis technique?', '[{"id": "a", "text": "This finding is more consistent with Avoidance list."}, {"id": "b", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "c", "text": "Patient is semi-recumbent at 45°, needle subxiphoid toward left shoulder."}, {"id": "d", "text": "Prone positioning is preferred for tamponade aspiration in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Patient is semi-recumbent at 45°, needle subxiphoid toward left shoulder. Anticipate setup details to reduce delay during emergency decompression.', 'Cardiac Tamponade - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Small-volume benefit?', 'Which clinical judgment is most consistent with Small-volume benefit?', '[{"id": "a", "text": "Drainage has no immediate effect on output in this note."}, {"id": "b", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "c", "text": "This finding is more consistent with Surgical option."}, {"id": "d", "text": "Recognize that early partial decompression can rapidly stabilize perfusion."}]'::jsonb, '["d"]'::jsonb, 'Correct because Removing even 20–50 mL can significantly increase cardiac output. Recognize that early partial decompression can rapidly stabilize perfusion.', 'Cardiac Tamponade - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Fluid analysis?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Fluid analysis?', '[{"id": "a", "text": "Pericardial fluid should be sent for culture, cytology, and chemistry."}, {"id": "b", "text": "Pericardial fluid analysis is unnecessary after aspiration in this note."}, {"id": "c", "text": "Only glucose is sent, with no culture/cytology/chemistry in this note."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericardial fluid should be sent for culture, cytology, and chemistry. Pair emergency stabilization with etiology workup.', 'Cardiac Tamponade - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Supportive preload strategy?', 'During rapid handoff, which interpretation is most accurate for Supportive preload strategy?', '[{"id": "a", "text": "This finding is more consistent with Post-procedure monitoring."}, {"id": "b", "text": "All preload support is contraindicated in tamponade in this note."}, {"id": "c", "text": "Maintain filling while arranging definitive decompression."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because IV fluid bolus is used to maintain preload in tamponade. Maintain filling while arranging definitive decompression.', 'Cardiac Tamponade - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Avoidance list?', 'The nurse must prioritize interventions. Which statement best reflects Avoidance list?', '[{"id": "a", "text": "High-dose vasodilators are first-line tamponade stabilizers in this note."}, {"id": "b", "text": "This finding is more consistent with Differentiation clue."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Avoid diuretics and vasodilators; avoid positive pressure ventilation when possible due to reduced venous return."}]'::jsonb, '["d"]'::jsonb, 'Correct because Avoid diuretics and vasodilators; avoid positive pressure ventilation when possible due to reduced venous return. Prevent iatrogenic preload reduction in unstable tamponade.', 'Cardiac Tamponade - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Surgical option?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Surgical option?', '[{"id": "a", "text": "Recurrence is impossible after one aspiration according to this note."}, {"id": "b", "text": "Plan recurrence management beyond initial aspiration."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pericardial window is considered for recurrent tamponade. Plan recurrence management beyond initial aspiration.', 'Cardiac Tamponade - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with NCLEX first action?', 'Which clinical judgment is most consistent with NCLEX first action?', '[{"id": "a", "text": "Routine discharge teaching is first action in this note."}, {"id": "b", "text": "This finding is more consistent with Hemodynamic mechanism."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "First action is immediate provider notification and preparation for pericardiocentesis."}]'::jsonb, '["d"]'::jsonb, 'Correct because First action is immediate provider notification and preparation for pericardiocentesis. Do not delay life-saving decompression for low-yield tasks.', 'Cardiac Tamponade - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Post-procedure monitoring?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Post-procedure monitoring?', '[{"id": "a", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "b", "text": "Sustain surveillance after initial stabilization."}, {"id": "c", "text": "Recurrence is not possible post-procedure in this note."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because After pericardiocentesis, monitor for re-accumulation because symptoms can return. Sustain surveillance after initial stabilization.', 'Cardiac Tamponade - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Differentiation clue?', 'During rapid handoff, which interpretation is most accurate for Differentiation clue?', '[{"id": "a", "text": "The note states tamponade chest pain worsens during expiration and coughing; cough is not typical of MI."}, {"id": "b", "text": "This finding is more consistent with Cause profile."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}]'::jsonb, '["a"]'::jsonb, 'Correct because The note states tamponade chest pain worsens during expiration and coughing; cough is not typical of MI. Use distinguishing chest pain pattern and associated symptoms for differential prioritization.', 'Cardiac Tamponade - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Definition?', 'The nurse must prioritize interventions. Which statement best reflects Definition?', '[{"id": "a", "text": "Treat as an emergency because rapid deterioration and arrest can occur."}, {"id": "b", "text": "Tamponade improves ventricular filling and raises cardiac output."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Tamponade is a benign condition that can always wait for routine follow-up."}]'::jsonb, '["a"]'::jsonb, 'Correct because Cardiac tamponade is fluid accumulation in the pericardial sac that compresses the heart. Treat as an emergency because rapid deterioration and arrest can occur.', 'Cardiac Tamponade - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Hemodynamic mechanism?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Hemodynamic mechanism?', '[{"id": "a", "text": "Tamponade increases preload by compressing the ventricles."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "This finding is more consistent with Beck triad."}, {"id": "d", "text": "Increased intrapericardial pressure compresses all four chambers and causes obstructive shock."}]'::jsonb, '["d"]'::jsonb, 'Correct because Increased intrapericardial pressure compresses all four chambers and causes obstructive shock. Recognize obstructive shock pattern when hypotension and poor perfusion progress.', 'Cardiac Tamponade - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Acute volume threshold?', 'Which clinical judgment is most consistent with Acute volume threshold?', '[{"id": "a", "text": "This finding is more consistent with Muffled heart sounds meaning."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Do not underestimate small but rapidly accumulating effusions."}]'::jsonb, '["d"]'::jsonb, 'Correct because As little as 150–200 mL acutely accumulated fluid can cause tamponade. Do not underestimate small but rapidly accumulating effusions.', 'Cardiac Tamponade - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Cause profile?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Cause profile?', '[{"id": "a", "text": "Aortic dissection is excluded as a tamponade cause in this note."}, {"id": "b", "text": "This finding is more consistent with JVD mechanism."}, {"id": "c", "text": "Tamponade is only caused by isolated dehydration in this note."}, {"id": "d", "text": "Pericarditis is the most common cause, with trauma, post-op bleeding, malignancy, and aortic dissection also listed."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericarditis is the most common cause, with trauma, post-op bleeding, malignancy, and aortic dissection also listed. Screen etiology rapidly while preparing definitive decompression.', 'Cardiac Tamponade - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Additional causes?', 'During rapid handoff, which interpretation is most accurate for Additional causes?', '[{"id": "a", "text": "Tamponade causes are limited to congenital defects in this note."}, {"id": "b", "text": "Radiation therapy cannot contribute to tamponade in this note."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Integrate procedural and systemic risk factors into rapid triage."}]'::jsonb, '["d"]'::jsonb, 'Correct because Additional causes include MI free-wall rupture, iatrogenic catheterization complications, SLE, uremia, and radiation therapy. Integrate procedural and systemic risk factors into rapid triage.', 'Cardiac Tamponade - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Beck triad?', 'The nurse must prioritize interventions. Which statement best reflects Beck triad?', '[{"id": "a", "text": "Beck triad consists of muffled heart sounds, JVD, and hypotension."}, {"id": "b", "text": "Hypertension is part of Beck triad in this note."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Wheezing replaces JVD in Beck triad in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Beck triad consists of muffled heart sounds, JVD, and hypotension. Escalate immediately when triad features cluster together.', 'Cardiac Tamponade - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Muffled heart sounds meaning?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Muffled heart sounds meaning?', '[{"id": "a", "text": "Correlate difficult auscultation with other tamponade signs rather than dismissing technique."}, {"id": "b", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "c", "text": "This finding is more consistent with Compensatory tachycardia."}, {"id": "d", "text": "Muffled sounds indicate hyperdynamic output in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Muffled tones occur because pericardial fluid dampens auscultated sounds. Correlate difficult auscultation with other tamponade signs rather than dismissing technique.', 'Cardiac Tamponade - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with JVD mechanism?', 'Which clinical judgment is most consistent with JVD mechanism?', '[{"id": "a", "text": "JVD in tamponade represents low venous pressure in this note."}, {"id": "b", "text": "JVD reflects impaired right-heart filling and backed-up venous pressure."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}]'::jsonb, '["b"]'::jsonb, 'Correct because JVD reflects impaired right-heart filling and backed-up venous pressure. Use venous congestion findings to support obstructive physiology.', 'Cardiac Tamponade - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Hypotension pattern?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Hypotension pattern?', '[{"id": "a", "text": "Treat narrowing pulse pressure with falling BP as decompensation."}, {"id": "b", "text": "This finding is more consistent with Respiratory/general signs."}, {"id": "c", "text": "Tamponade typically causes widened pulse pressure in this note."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["a"]'::jsonb, 'Correct because Hypotension occurs from reduced cardiac output and often presents with narrow pulse pressure. Treat narrowing pulse pressure with falling BP as decompensation.', 'Cardiac Tamponade - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Pulsus paradoxus?', 'During rapid handoff, which interpretation is most accurate for Pulsus paradoxus?', '[{"id": "a", "text": "This finding is more consistent with Electrical alternans."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "Pulsus paradoxus is a >10 mmHg systolic BP drop during inspiration."}, {"id": "d", "text": "Pulsus paradoxus is defined as a diastolic rise in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pulsus paradoxus is a >10 mmHg systolic BP drop during inspiration. Use this measurement to reinforce tamponade suspicion in unstable patients.', 'Cardiac Tamponade - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Compensatory tachycardia?', 'The nurse must prioritize interventions. Which statement best reflects Compensatory tachycardia?', '[{"id": "a", "text": "Heart rate has no monitoring value in tamponade in this note."}, {"id": "b", "text": "Bradycardia is the expected compensatory response in this note."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Interpret rising heart rate with perfusion decline as compensation failure risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because Tachycardia is listed as a compensatory sign in tamponade. Interpret rising heart rate with perfusion decline as compensation failure risk.', 'Cardiac Tamponade - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Perfusion decline?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Perfusion decline?', '[{"id": "a", "text": "Cool clammy skin and decreased urine output are signs of shock/perfusion compromise."}, {"id": "b", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "c", "text": "Warm dry skin is listed as hallmark obstructive shock in this note."}, {"id": "d", "text": "This finding is more consistent with Echo diagnosis."}]'::jsonb, '["a"]'::jsonb, 'Correct because Cool clammy skin and decreased urine output are signs of shock/perfusion compromise. Prioritize perfusion rescue and definitive decompression.', 'Cardiac Tamponade - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Respiratory/general signs?', 'Which clinical judgment is most consistent with Respiratory/general signs?', '[{"id": "a", "text": "Dysphagia cannot occur with larger effusions in this note."}, {"id": "b", "text": "This finding is more consistent with Chest X-ray clue."}, {"id": "c", "text": "Interpret escalating respiratory distress and anxiety as potential hemodynamic deterioration."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dyspnea, orthopnea, anxiety/restlessness, and possible dysphagia are listed additional findings. Interpret escalating respiratory distress and anxiety as potential hemodynamic deterioration.', 'Cardiac Tamponade - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Electrical alternans?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Electrical alternans?', '[{"id": "a", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "b", "text": "Electrical alternans (alternating QRS amplitude) is pathognomonic and tamponade until proven otherwise."}, {"id": "c", "text": "This finding is more consistent with Pericardiocentesis emergency."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Electrical alternans (alternating QRS amplitude) is pathognomonic and tamponade until proven otherwise. Treat electrical alternans as a red-flag trigger for immediate escalation.', 'Cardiac Tamponade - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Other EKG clues?', 'During rapid handoff, which interpretation is most accurate for Other EKG clues?', '[{"id": "a", "text": "High-voltage QRS is the defining tamponade pattern in this note."}, {"id": "b", "text": "Integrate EKG pattern with etiology and bedside instability."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["b"]'::jsonb, 'Correct because Low-voltage QRS and sinus tachycardia are common; diffuse ST elevation can appear if pericarditis is the cause. Integrate EKG pattern with etiology and bedside instability.', 'Cardiac Tamponade - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Echo diagnosis?', 'The nurse must prioritize interventions. Which statement best reflects Echo diagnosis?', '[{"id": "a", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "b", "text": "Echo has no role in tamponade diagnosis in this note."}, {"id": "c", "text": "Echocardiogram is the gold standard and shows effusion with chamber compression."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because Echocardiogram is the gold standard and shows effusion with chamber compression. Expedite bedside echo in unstable patients with suspected tamponade.', 'Cardiac Tamponade - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Chest X-ray clue?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Chest X-ray clue?', '[{"id": "a", "text": "This finding is more consistent with Fluid analysis."}, {"id": "b", "text": "Water-bottle silhouette confirms acute coronary occlusion in this note."}, {"id": "c", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "d", "text": "Use X-ray as supportive evidence, not a delay to treatment."}]'::jsonb, '["d"]'::jsonb, 'Correct because Chest X-ray may show an enlarged water-bottle cardiac silhouette. Use X-ray as supportive evidence, not a delay to treatment.', 'Cardiac Tamponade - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Pericardiocentesis emergency?', 'Which clinical judgment is most consistent with Pericardiocentesis emergency?', '[{"id": "a", "text": "This finding is more consistent with Supportive preload strategy."}, {"id": "b", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "c", "text": "Immediate pericardiocentesis is the emergency treatment."}, {"id": "d", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}]'::jsonb, '["c"]'::jsonb, 'Correct because Immediate pericardiocentesis is the emergency treatment. Prepare urgently and do not delay for nonessential steps.', 'Cardiac Tamponade - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Pericardiocentesis technique?', 'A patient in acute cardiovascular decline is reassessed. Which finding best supports Pericardiocentesis technique?', '[{"id": "a", "text": "This finding is more consistent with Avoidance list."}, {"id": "b", "text": "Needle is directed toward the right hip in this note."}, {"id": "c", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}, {"id": "d", "text": "Anticipate setup details to reduce delay during emergency decompression."}]'::jsonb, '["d"]'::jsonb, 'Correct because Patient is semi-recumbent at 45°, needle subxiphoid toward left shoulder. Anticipate setup details to reduce delay during emergency decompression.', 'Cardiac Tamponade - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During rapid handoff, which interpretation is most accurate for Small-volume benefit?', 'During rapid handoff, which interpretation is most accurate for Small-volume benefit?', '[{"id": "a", "text": "Removing even 20–50 mL can significantly increase cardiac output."}, {"id": "b", "text": "Drainage has no immediate effect on output in this note."}, {"id": "c", "text": "At least 1 liter must be removed before hemodynamics improve in this note."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["a"]'::jsonb, 'Correct because Removing even 20–50 mL can significantly increase cardiac output. Recognize that early partial decompression can rapidly stabilize perfusion.', 'Cardiac Tamponade - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse must prioritize interventions. Which statement best reflects Fluid analysis?', 'The nurse must prioritize interventions. Which statement best reflects Fluid analysis?', '[{"id": "a", "text": "Pair emergency stabilization with etiology workup."}, {"id": "b", "text": "This finding is more consistent with NCLEX first action."}, {"id": "c", "text": "Pericardial fluid analysis is unnecessary after aspiration in this note."}, {"id": "d", "text": "Only glucose is sent, with no culture/cytology/chemistry in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericardial fluid should be sent for culture, cytology, and chemistry. Pair emergency stabilization with etiology workup.', 'Cardiac Tamponade - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Supportive preload strategy?', 'A high-acuity symptom cluster is reviewed. Which conclusion best matches Supportive preload strategy?', '[{"id": "a", "text": "All preload support is contraindicated in tamponade in this note."}, {"id": "b", "text": "This finding is more consistent with Post-procedure monitoring."}, {"id": "c", "text": "IV fluid bolus is used to maintain preload in tamponade."}, {"id": "d", "text": "Immediate deterioration risk is low, so urgent escalation is unnecessary."}]'::jsonb, '["c"]'::jsonb, 'Correct because IV fluid bolus is used to maintain preload in tamponade. Maintain filling while arranging definitive decompression.', 'Cardiac Tamponade - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most consistent with Avoidance list?', 'Which clinical judgment is most consistent with Avoidance list?', '[{"id": "a", "text": "Preload reduction is preferred before confirming diagnosis in unstable cases."}, {"id": "b", "text": "Positive pressure ventilation always improves tamponade preload in this note."}, {"id": "c", "text": "This finding is more consistent with Differentiation clue."}, {"id": "d", "text": "Prevent iatrogenic preload reduction in unstable tamponade."}]'::jsonb, '["d"]'::jsonb, 'Correct because Avoid diuretics and vasodilators; avoid positive pressure ventilation when possible due to reduced venous return. Prevent iatrogenic preload reduction in unstable tamponade.', 'Cardiac Tamponade - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Definition. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Definition. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Tamponade is a benign condition that can always wait for routine follow-up."}, {"id": "b", "text": "Cardiac output falls when ventricular filling is impaired."}, {"id": "c", "text": "Tamponade involves pericardial fluid compressing cardiac chambers."}, {"id": "d", "text": "Tamponade improves ventricular filling and raises cardiac output."}, {"id": "e", "text": "Untreated tamponade can be rapidly fatal."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiac tamponade is fluid accumulation in the pericardial sac that compresses the heart.', 'Cardiac Tamponade - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Hemodynamic mechanism, which statements are correct? (Select all that apply)', 'For a patient with suspected Hemodynamic mechanism, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Tamponade can produce obstructive shock physiology."}, {"id": "b", "text": "Reduced preload leads to reduced cardiac output."}, {"id": "c", "text": "Tamponade is primarily distributive shock from vasodilation in this note."}, {"id": "d", "text": "Rising intrapericardial pressure limits chamber filling."}, {"id": "e", "text": "Tamponade increases preload by compressing the ventricles."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Increased intrapericardial pressure compresses all four chambers and causes obstructive shock.', 'Cardiac Tamponade - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Acute volume threshold. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Acute volume threshold. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Only massive chronic effusions can cause tamponade in this note."}, {"id": "b", "text": "A relatively small acute effusion can be dangerous."}, {"id": "c", "text": "Volume rate of accumulation is irrelevant in tamponade risk."}, {"id": "d", "text": "Rapid accumulation allows less compensation time."}, {"id": "e", "text": "Clinical deterioration depends on accumulation speed, not only total volume."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: As little as 150–200 mL acutely accumulated fluid can cause tamponade.', 'Cardiac Tamponade - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Cause profile, which points are accurate? (Select all that apply)', 'During patient teaching about Cause profile, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Pericarditis is listed as the most common cause."}, {"id": "b", "text": "Malignancy and post-cardiac surgery are recognized causes."}, {"id": "c", "text": "Tamponade is only caused by isolated dehydration in this note."}, {"id": "d", "text": "Aortic dissection is excluded as a tamponade cause in this note."}, {"id": "e", "text": "Penetrating or blunt trauma can precipitate tamponade."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis is the most common cause, with trauma, post-op bleeding, malignancy, and aortic dissection also listed.', 'Cardiac Tamponade - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Additional causes? (Select all that apply)', 'Which assessment findings support Additional causes? (Select all that apply)', '[{"id": "a", "text": "MI free-wall rupture is listed as a cause."}, {"id": "b", "text": "Tamponade causes are limited to congenital defects in this note."}, {"id": "c", "text": "Iatrogenic catheter-related complications can cause tamponade."}, {"id": "d", "text": "Radiation therapy cannot contribute to tamponade in this note."}, {"id": "e", "text": "Autoimmune disease and uremia are included causes."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Additional causes include MI free-wall rupture, iatrogenic catheterization complications, SLE, uremia, and radiation therapy.', 'Cardiac Tamponade - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Beck triad. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Beck triad. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "JVD is part of Beck triad."}, {"id": "b", "text": "Hypotension is part of Beck triad."}, {"id": "c", "text": "Wheezing replaces JVD in Beck triad in this note."}, {"id": "d", "text": "Muffled heart sounds are part of Beck triad."}, {"id": "e", "text": "Hypertension is part of Beck triad in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Beck triad consists of muffled heart sounds, JVD, and hypotension.', 'Cardiac Tamponade - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Muffled heart sounds meaning, which statements are correct? (Select all that apply)', 'For a patient with suspected Muffled heart sounds meaning, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Muffled tones should be interpreted alongside hypotension and JVD."}, {"id": "b", "text": "Auscultation findings can be subtle but clinically important."}, {"id": "c", "text": "Muffled sounds indicate hyperdynamic output in this note."}, {"id": "d", "text": "Muffled tones rule out tamponade in this note."}, {"id": "e", "text": "Fluid around the heart can dampen heart sounds."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Muffled tones occur because pericardial fluid dampens auscultated sounds.', 'Cardiac Tamponade - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for JVD mechanism. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for JVD mechanism. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "JVD is unrelated to right-heart filling in this note."}, {"id": "b", "text": "Backed-up venous pressure can appear as neck vein distension."}, {"id": "c", "text": "JVD in tamponade represents low venous pressure in this note."}, {"id": "d", "text": "JVD is a high-yield bedside tamponade clue."}, {"id": "e", "text": "Impaired right-heart filling contributes to JVD."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: JVD reflects impaired right-heart filling and backed-up venous pressure.', 'Cardiac Tamponade - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Hypotension pattern, which points are accurate? (Select all that apply)', 'During patient teaching about Hypotension pattern, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Hypotension should prompt emergency intervention readiness."}, {"id": "b", "text": "Tamponade typically causes widened pulse pressure in this note."}, {"id": "c", "text": "Hypotension is not expected in tamponade according to this note."}, {"id": "d", "text": "Narrow pulse pressure can occur in tamponade."}, {"id": "e", "text": "Reduced cardiac output contributes to hypotension."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Hypotension occurs from reduced cardiac output and often presents with narrow pulse pressure.', 'Cardiac Tamponade - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Pulsus paradoxus? (Select all that apply)', 'Which assessment findings support Pulsus paradoxus? (Select all that apply)', '[{"id": "a", "text": "Pulsus paradoxus supports tamponade assessment."}, {"id": "b", "text": "A >10 mmHg inspiratory systolic drop indicates pulsus paradoxus."}, {"id": "c", "text": "Pulsus paradoxus is defined as a diastolic rise in this note."}, {"id": "d", "text": "A 2 mmHg inspiratory change defines pulsus paradoxus in this note."}, {"id": "e", "text": "Inspiratory BP variation is specifically emphasized in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pulsus paradoxus is a >10 mmHg systolic BP drop during inspiration.', 'Cardiac Tamponade - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Compensatory tachycardia. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Compensatory tachycardia. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Heart rate has no monitoring value in tamponade in this note."}, {"id": "b", "text": "Bradycardia is the expected compensatory response in this note."}, {"id": "c", "text": "Trend vitals rather than evaluating heart rate in isolation."}, {"id": "d", "text": "Tachycardia can be a compensatory response in tamponade."}, {"id": "e", "text": "Compensation may coexist with hypotension as condition worsens."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Tachycardia is listed as a compensatory sign in tamponade.', 'Cardiac Tamponade - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Perfusion decline, which statements are correct? (Select all that apply)', 'For a patient with suspected Perfusion decline, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Cool clammy skin can indicate shock in tamponade."}, {"id": "b", "text": "Increased urine output is expected in tamponade shock in this note."}, {"id": "c", "text": "Urine output may decrease with low cardiac output."}, {"id": "d", "text": "Warm dry skin is listed as hallmark obstructive shock in this note."}, {"id": "e", "text": "Perfusion signs should be trended urgently."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Cool clammy skin and decreased urine output are signs of shock/perfusion compromise.', 'Cardiac Tamponade - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Respiratory/general signs. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Respiratory/general signs. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Dysphagia cannot occur with larger effusions in this note."}, {"id": "b", "text": "Tamponade in this note is always asymptomatic until arrest."}, {"id": "c", "text": "Anxiety and restlessness are compatible with acute instability."}, {"id": "d", "text": "Orthopnea can be present in tamponade."}, {"id": "e", "text": "Dyspnea may occur with tamponade."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dyspnea, orthopnea, anxiety/restlessness, and possible dysphagia are listed additional findings.', 'Cardiac Tamponade - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Electrical alternans, which points are accurate? (Select all that apply)', 'During patient teaching about Electrical alternans, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Alternans excludes pericardial fluid in this note."}, {"id": "b", "text": "Alternans should trigger urgent provider notification and prep for intervention."}, {"id": "c", "text": "Electrical alternans strongly supports tamponade in this note."}, {"id": "d", "text": "Electrical alternans is a benign normal variant in this note."}, {"id": "e", "text": "Electrical alternans is beat-to-beat QRS amplitude variation."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Electrical alternans (alternating QRS amplitude) is pathognomonic and tamponade until proven otherwise.', 'Cardiac Tamponade - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Other EKG clues? (Select all that apply)', 'Which assessment findings support Other EKG clues? (Select all that apply)', '[{"id": "a", "text": "Sinus tachycardia is a common rhythm finding."}, {"id": "b", "text": "Tamponade cannot coexist with pericarditis EKG changes in this note."}, {"id": "c", "text": "High-voltage QRS is the defining tamponade pattern in this note."}, {"id": "d", "text": "Diffuse ST elevation may occur when pericarditis underlies tamponade."}, {"id": "e", "text": "Low-voltage QRS can appear in tamponade."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Low-voltage QRS and sinus tachycardia are common; diffuse ST elevation can appear if pericarditis is the cause.', 'Cardiac Tamponade - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Echo diagnosis. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Echo diagnosis. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Echo findings guide urgent decompression decisions."}, {"id": "b", "text": "Echocardiography is the gold-standard diagnostic test."}, {"id": "c", "text": "Echo can show pericardial effusion and chamber compression."}, {"id": "d", "text": "Echo has no role in tamponade diagnosis in this note."}, {"id": "e", "text": "Chest X-ray is the gold standard in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Echocardiogram is the gold standard and shows effusion with chamber compression.', 'Cardiac Tamponade - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Chest X-ray clue, which statements are correct? (Select all that apply)', 'For a patient with suspected Chest X-ray clue, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "A water-bottle silhouette can support tamponade suspicion."}, {"id": "b", "text": "Normal silhouette excludes tamponade in this note."}, {"id": "c", "text": "Water-bottle silhouette confirms acute coronary occlusion in this note."}, {"id": "d", "text": "Imaging should be integrated with hemodynamics and bedside findings."}, {"id": "e", "text": "X-ray is supportive but not the definitive emergent test."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Chest X-ray may show an enlarged water-bottle cardiac silhouette.', 'Cardiac Tamponade - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Pericardiocentesis emergency. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Pericardiocentesis emergency. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Pericardiocentesis should be deferred until routine clinic follow-up."}, {"id": "b", "text": "Rapid decompression can be lifesaving in tamponade."}, {"id": "c", "text": "Pericardiocentesis is the immediate definitive intervention."}, {"id": "d", "text": "Diuretics alone are definitive first-line emergency treatment in this note."}, {"id": "e", "text": "Urgent provider notification and procedural preparation are priorities."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Immediate pericardiocentesis is the emergency treatment.', 'Cardiac Tamponade - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Pericardiocentesis technique, which points are accurate? (Select all that apply)', 'During patient teaching about Pericardiocentesis technique, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Needle is directed toward the right hip in this note."}, {"id": "b", "text": "Subxiphoid entry directed toward the left shoulder is described."}, {"id": "c", "text": "Semi-recumbent positioning at about 45° is listed."}, {"id": "d", "text": "Prone positioning is preferred for tamponade aspiration in this note."}, {"id": "e", "text": "Procedure setup should be rapid and organized."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Patient is semi-recumbent at 45°, needle subxiphoid toward left shoulder.', 'Cardiac Tamponade - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Small-volume benefit? (Select all that apply)', 'Which assessment findings support Small-volume benefit? (Select all that apply)', '[{"id": "a", "text": "Drainage has no immediate effect on output in this note."}, {"id": "b", "text": "Small-volume drainage can produce meaningful hemodynamic improvement."}, {"id": "c", "text": "At least 1 liter must be removed before hemodynamics improve in this note."}, {"id": "d", "text": "Clinical response should be reassessed continuously after drainage."}, {"id": "e", "text": "Cardiac output may rise after limited fluid removal."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Removing even 20–50 mL can significantly increase cardiac output.', 'Cardiac Tamponade - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Fluid analysis. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Fluid analysis. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Only glucose is sent, with no culture/cytology/chemistry in this note."}, {"id": "b", "text": "Culture is part of fluid analysis."}, {"id": "c", "text": "Pericardial fluid analysis is unnecessary after aspiration in this note."}, {"id": "d", "text": "Chemistry testing is part of fluid analysis."}, {"id": "e", "text": "Cytology is part of fluid analysis."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericardial fluid should be sent for culture, cytology, and chemistry.', 'Cardiac Tamponade - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Supportive preload strategy, which statements are correct? (Select all that apply)', 'For a patient with suspected Supportive preload strategy, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Preload support can temporarily improve hemodynamics."}, {"id": "b", "text": "Supportive therapy does not replace urgent pericardiocentesis."}, {"id": "c", "text": "All preload support is contraindicated in tamponade in this note."}, {"id": "d", "text": "IV fluids may support preload in tamponade."}, {"id": "e", "text": "Tamponade management in this note avoids all IV fluid administration."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: IV fluid bolus is used to maintain preload in tamponade.', 'Cardiac Tamponade - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Avoidance list. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Avoidance list. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "High-dose vasodilators are first-line tamponade stabilizers in this note."}, {"id": "b", "text": "Positive pressure ventilation may reduce venous return and should be avoided if possible."}, {"id": "c", "text": "Vasodilators can worsen hemodynamics by reducing preload."}, {"id": "d", "text": "Positive pressure ventilation always improves tamponade preload in this note."}, {"id": "e", "text": "Diuretics can worsen preload in tamponade."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Avoid diuretics and vasodilators; avoid positive pressure ventilation when possible due to reduced venous return.', 'Cardiac Tamponade - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Surgical option, which points are accurate? (Select all that apply)', 'During patient teaching about Surgical option, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Pericardial window is contraindicated in recurrent tamponade in this note."}, {"id": "b", "text": "Definitive surgical drainage may be needed after repeated episodes."}, {"id": "c", "text": "Pericardial window is listed for recurrent tamponade."}, {"id": "d", "text": "Recurrence risk requires ongoing follow-up planning."}, {"id": "e", "text": "Recurrence is impossible after one aspiration according to this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Pericardial window is considered for recurrent tamponade.', 'Cardiac Tamponade - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support NCLEX first action? (Select all that apply)', 'Which assessment findings support NCLEX first action? (Select all that apply)', '[{"id": "a", "text": "Observation-only management is adequate in suspected tamponade in this note."}, {"id": "b", "text": "Delay can lead to arrest within minutes."}, {"id": "c", "text": "Routine discharge teaching is first action in this note."}, {"id": "d", "text": "Preparation for pericardiocentesis is urgent."}, {"id": "e", "text": "Immediate provider notification is prioritized."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: First action is immediate provider notification and preparation for pericardiocentesis.', 'Cardiac Tamponade - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Post-procedure monitoring. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Post-procedure monitoring. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Symptoms can recur due to fluid re-accumulation."}, {"id": "b", "text": "Post-procedure monitoring is essential."}, {"id": "c", "text": "No monitoring is needed after successful aspiration in this note."}, {"id": "d", "text": "Recurrence is not possible post-procedure in this note."}, {"id": "e", "text": "Reassessment should include recurring hypotension/JVD/muffled tones signs."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: After pericardiocentesis, monitor for re-accumulation because symptoms can return.', 'Cardiac Tamponade - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Differentiation clue, which statements are correct? (Select all that apply)', 'For a patient with suspected Differentiation clue, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Tamponade/pericardial pain may worsen with coughing in this note."}, {"id": "b", "text": "The note contrasts this pattern with typical MI presentation."}, {"id": "c", "text": "Differential reasoning should incorporate associated respiratory features."}, {"id": "d", "text": "The note says cough is a classic MI hallmark finding."}, {"id": "e", "text": "Tamponade pain is unrelated to breathing/cough in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: The note states tamponade chest pain worsens during expiration and coughing; cough is not typical of MI.', 'Cardiac Tamponade - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Definition. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Definition. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Untreated tamponade can be rapidly fatal."}, {"id": "b", "text": "Tamponade is a benign condition that can always wait for routine follow-up."}, {"id": "c", "text": "Cardiac output falls when ventricular filling is impaired."}, {"id": "d", "text": "Tamponade improves ventricular filling and raises cardiac output."}, {"id": "e", "text": "Tamponade involves pericardial fluid compressing cardiac chambers."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiac tamponade is fluid accumulation in the pericardial sac that compresses the heart.', 'Cardiac Tamponade - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Hemodynamic mechanism, which points are accurate? (Select all that apply)', 'During patient teaching about Hemodynamic mechanism, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Tamponade increases preload by compressing the ventricles."}, {"id": "b", "text": "Tamponade is primarily distributive shock from vasodilation in this note."}, {"id": "c", "text": "Rising intrapericardial pressure limits chamber filling."}, {"id": "d", "text": "Tamponade can produce obstructive shock physiology."}, {"id": "e", "text": "Reduced preload leads to reduced cardiac output."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Increased intrapericardial pressure compresses all four chambers and causes obstructive shock.', 'Cardiac Tamponade - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Acute volume threshold? (Select all that apply)', 'Which assessment findings support Acute volume threshold? (Select all that apply)', '[{"id": "a", "text": "Only massive chronic effusions can cause tamponade in this note."}, {"id": "b", "text": "Volume rate of accumulation is irrelevant in tamponade risk."}, {"id": "c", "text": "Clinical deterioration depends on accumulation speed, not only total volume."}, {"id": "d", "text": "Rapid accumulation allows less compensation time."}, {"id": "e", "text": "A relatively small acute effusion can be dangerous."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: As little as 150–200 mL acutely accumulated fluid can cause tamponade.', 'Cardiac Tamponade - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Cause profile. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Cause profile. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Tamponade is only caused by isolated dehydration in this note."}, {"id": "b", "text": "Malignancy and post-cardiac surgery are recognized causes."}, {"id": "c", "text": "Pericarditis is listed as the most common cause."}, {"id": "d", "text": "Aortic dissection is excluded as a tamponade cause in this note."}, {"id": "e", "text": "Penetrating or blunt trauma can precipitate tamponade."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis is the most common cause, with trauma, post-op bleeding, malignancy, and aortic dissection also listed.', 'Cardiac Tamponade - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Additional causes, which statements are correct? (Select all that apply)', 'For a patient with suspected Additional causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "MI free-wall rupture is listed as a cause."}, {"id": "b", "text": "Radiation therapy cannot contribute to tamponade in this note."}, {"id": "c", "text": "Autoimmune disease and uremia are included causes."}, {"id": "d", "text": "Tamponade causes are limited to congenital defects in this note."}, {"id": "e", "text": "Iatrogenic catheter-related complications can cause tamponade."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Additional causes include MI free-wall rupture, iatrogenic catheterization complications, SLE, uremia, and radiation therapy.', 'Cardiac Tamponade - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Beck triad. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Beck triad. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Wheezing replaces JVD in Beck triad in this note."}, {"id": "b", "text": "Hypertension is part of Beck triad in this note."}, {"id": "c", "text": "Muffled heart sounds are part of Beck triad."}, {"id": "d", "text": "JVD is part of Beck triad."}, {"id": "e", "text": "Hypotension is part of Beck triad."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Beck triad consists of muffled heart sounds, JVD, and hypotension.', 'Cardiac Tamponade - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Muffled heart sounds meaning, which points are accurate? (Select all that apply)', 'During patient teaching about Muffled heart sounds meaning, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Auscultation findings can be subtle but clinically important."}, {"id": "b", "text": "Muffled tones should be interpreted alongside hypotension and JVD."}, {"id": "c", "text": "Fluid around the heart can dampen heart sounds."}, {"id": "d", "text": "Muffled sounds indicate hyperdynamic output in this note."}, {"id": "e", "text": "Muffled tones rule out tamponade in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Muffled tones occur because pericardial fluid dampens auscultated sounds.', 'Cardiac Tamponade - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support JVD mechanism? (Select all that apply)', 'Which assessment findings support JVD mechanism? (Select all that apply)', '[{"id": "a", "text": "JVD in tamponade represents low venous pressure in this note."}, {"id": "b", "text": "Backed-up venous pressure can appear as neck vein distension."}, {"id": "c", "text": "Impaired right-heart filling contributes to JVD."}, {"id": "d", "text": "JVD is a high-yield bedside tamponade clue."}, {"id": "e", "text": "JVD is unrelated to right-heart filling in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: JVD reflects impaired right-heart filling and backed-up venous pressure.', 'Cardiac Tamponade - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Hypotension pattern. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Hypotension pattern. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Narrow pulse pressure can occur in tamponade."}, {"id": "b", "text": "Tamponade typically causes widened pulse pressure in this note."}, {"id": "c", "text": "Hypotension should prompt emergency intervention readiness."}, {"id": "d", "text": "Reduced cardiac output contributes to hypotension."}, {"id": "e", "text": "Hypotension is not expected in tamponade according to this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypotension occurs from reduced cardiac output and often presents with narrow pulse pressure.', 'Cardiac Tamponade - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Pulsus paradoxus, which statements are correct? (Select all that apply)', 'For a patient with suspected Pulsus paradoxus, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pulsus paradoxus supports tamponade assessment."}, {"id": "b", "text": "A 2 mmHg inspiratory change defines pulsus paradoxus in this note."}, {"id": "c", "text": "Pulsus paradoxus is defined as a diastolic rise in this note."}, {"id": "d", "text": "Inspiratory BP variation is specifically emphasized in this note."}, {"id": "e", "text": "A >10 mmHg inspiratory systolic drop indicates pulsus paradoxus."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pulsus paradoxus is a >10 mmHg systolic BP drop during inspiration.', 'Cardiac Tamponade - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Compensatory tachycardia. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Compensatory tachycardia. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Tachycardia can be a compensatory response in tamponade."}, {"id": "b", "text": "Bradycardia is the expected compensatory response in this note."}, {"id": "c", "text": "Heart rate has no monitoring value in tamponade in this note."}, {"id": "d", "text": "Compensation may coexist with hypotension as condition worsens."}, {"id": "e", "text": "Trend vitals rather than evaluating heart rate in isolation."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Tachycardia is listed as a compensatory sign in tamponade.', 'Cardiac Tamponade - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Perfusion decline, which points are accurate? (Select all that apply)', 'During patient teaching about Perfusion decline, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Warm dry skin is listed as hallmark obstructive shock in this note."}, {"id": "b", "text": "Cool clammy skin can indicate shock in tamponade."}, {"id": "c", "text": "Urine output may decrease with low cardiac output."}, {"id": "d", "text": "Perfusion signs should be trended urgently."}, {"id": "e", "text": "Increased urine output is expected in tamponade shock in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Cool clammy skin and decreased urine output are signs of shock/perfusion compromise.', 'Cardiac Tamponade - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Respiratory/general signs? (Select all that apply)', 'Which assessment findings support Respiratory/general signs? (Select all that apply)', '[{"id": "a", "text": "Orthopnea can be present in tamponade."}, {"id": "b", "text": "Dyspnea may occur with tamponade."}, {"id": "c", "text": "Tamponade in this note is always asymptomatic until arrest."}, {"id": "d", "text": "Anxiety and restlessness are compatible with acute instability."}, {"id": "e", "text": "Dysphagia cannot occur with larger effusions in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Dyspnea, orthopnea, anxiety/restlessness, and possible dysphagia are listed additional findings.', 'Cardiac Tamponade - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Electrical alternans. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Electrical alternans. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Alternans excludes pericardial fluid in this note."}, {"id": "b", "text": "Electrical alternans is beat-to-beat QRS amplitude variation."}, {"id": "c", "text": "Electrical alternans is a benign normal variant in this note."}, {"id": "d", "text": "Alternans should trigger urgent provider notification and prep for intervention."}, {"id": "e", "text": "Electrical alternans strongly supports tamponade in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Electrical alternans (alternating QRS amplitude) is pathognomonic and tamponade until proven otherwise.', 'Cardiac Tamponade - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Other EKG clues, which statements are correct? (Select all that apply)', 'For a patient with suspected Other EKG clues, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Diffuse ST elevation may occur when pericarditis underlies tamponade."}, {"id": "b", "text": "High-voltage QRS is the defining tamponade pattern in this note."}, {"id": "c", "text": "Tamponade cannot coexist with pericarditis EKG changes in this note."}, {"id": "d", "text": "Sinus tachycardia is a common rhythm finding."}, {"id": "e", "text": "Low-voltage QRS can appear in tamponade."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Low-voltage QRS and sinus tachycardia are common; diffuse ST elevation can appear if pericarditis is the cause.', 'Cardiac Tamponade - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Echo diagnosis. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Echo diagnosis. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Echo has no role in tamponade diagnosis in this note."}, {"id": "b", "text": "Echocardiography is the gold-standard diagnostic test."}, {"id": "c", "text": "Echo can show pericardial effusion and chamber compression."}, {"id": "d", "text": "Chest X-ray is the gold standard in this note."}, {"id": "e", "text": "Echo findings guide urgent decompression decisions."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Echocardiogram is the gold standard and shows effusion with chamber compression.', 'Cardiac Tamponade - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Chest X-ray clue, which points are accurate? (Select all that apply)', 'During patient teaching about Chest X-ray clue, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Imaging should be integrated with hemodynamics and bedside findings."}, {"id": "b", "text": "Normal silhouette excludes tamponade in this note."}, {"id": "c", "text": "X-ray is supportive but not the definitive emergent test."}, {"id": "d", "text": "A water-bottle silhouette can support tamponade suspicion."}, {"id": "e", "text": "Water-bottle silhouette confirms acute coronary occlusion in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Chest X-ray may show an enlarged water-bottle cardiac silhouette.', 'Cardiac Tamponade - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Pericardiocentesis emergency? (Select all that apply)', 'Which assessment findings support Pericardiocentesis emergency? (Select all that apply)', '[{"id": "a", "text": "Pericardiocentesis should be deferred until routine clinic follow-up."}, {"id": "b", "text": "Pericardiocentesis is the immediate definitive intervention."}, {"id": "c", "text": "Urgent provider notification and procedural preparation are priorities."}, {"id": "d", "text": "Diuretics alone are definitive first-line emergency treatment in this note."}, {"id": "e", "text": "Rapid decompression can be lifesaving in tamponade."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Immediate pericardiocentesis is the emergency treatment.', 'Cardiac Tamponade - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A nurse is evaluating a patient for Pericardiocentesis technique. Which findings or actions are appropriate? (Select all that apply)', 'A nurse is evaluating a patient for Pericardiocentesis technique. Which findings or actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Subxiphoid entry directed toward the left shoulder is described."}, {"id": "b", "text": "Semi-recumbent positioning at about 45° is listed."}, {"id": "c", "text": "Prone positioning is preferred for tamponade aspiration in this note."}, {"id": "d", "text": "Procedure setup should be rapid and organized."}, {"id": "e", "text": "Needle is directed toward the right hip in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Patient is semi-recumbent at 45°, needle subxiphoid toward left shoulder.', 'Cardiac Tamponade - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For a patient with suspected Small-volume benefit, which statements are correct? (Select all that apply)', 'For a patient with suspected Small-volume benefit, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Small-volume drainage can produce meaningful hemodynamic improvement."}, {"id": "b", "text": "Cardiac output may rise after limited fluid removal."}, {"id": "c", "text": "Clinical response should be reassessed continuously after drainage."}, {"id": "d", "text": "Drainage has no immediate effect on output in this note."}, {"id": "e", "text": "At least 1 liter must be removed before hemodynamics improve in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Removing even 20–50 mL can significantly increase cardiac output.', 'Cardiac Tamponade - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The charge nurse audits care planning for Fluid analysis. Which items should be included? (Select all that apply)', 'The charge nurse audits care planning for Fluid analysis. Which items should be included? (Select all that apply)', '[{"id": "a", "text": "Chemistry testing is part of fluid analysis."}, {"id": "b", "text": "Only glucose is sent, with no culture/cytology/chemistry in this note."}, {"id": "c", "text": "Cytology is part of fluid analysis."}, {"id": "d", "text": "Culture is part of fluid analysis."}, {"id": "e", "text": "Pericardial fluid analysis is unnecessary after aspiration in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Pericardial fluid should be sent for culture, cytology, and chemistry.', 'Cardiac Tamponade - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During patient teaching about Supportive preload strategy, which points are accurate? (Select all that apply)', 'During patient teaching about Supportive preload strategy, which points are accurate? (Select all that apply)', '[{"id": "a", "text": "Preload support can temporarily improve hemodynamics."}, {"id": "b", "text": "Supportive therapy does not replace urgent pericardiocentesis."}, {"id": "c", "text": "Tamponade management in this note avoids all IV fluid administration."}, {"id": "d", "text": "IV fluids may support preload in tamponade."}, {"id": "e", "text": "All preload support is contraindicated in tamponade in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: IV fluid bolus is used to maintain preload in tamponade.', 'Cardiac Tamponade - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which assessment findings support Avoidance list? (Select all that apply)', 'Which assessment findings support Avoidance list? (Select all that apply)', '[{"id": "a", "text": "Positive pressure ventilation may reduce venous return and should be avoided if possible."}, {"id": "b", "text": "High-dose vasodilators are first-line tamponade stabilizers in this note."}, {"id": "c", "text": "Positive pressure ventilation always improves tamponade preload in this note."}, {"id": "d", "text": "Diuretics can worsen preload in tamponade."}, {"id": "e", "text": "Vasodilators can worsen hemodynamics by reducing preload."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Avoid diuretics and vasodilators; avoid positive pressure ventilation when possible due to reduced venous return.', 'Cardiac Tamponade - NCLEX', true, 100, 1, true);
END $$;
